<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    overflow: hidden;
    font-family: 'Ubuntu', 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
    user-select: none;
    height: 100vh;
    width: 100vw;
  }

  /* ── Desktop ─────────────────────────────────────── */
  #desktop {
    position: fixed;
    inset: 0;
    background: linear-gradient(135deg, #2c001e 0%, #4a0033 30%, #1a1a2e 70%, #16213e 100%);
    display: flex;
    flex-direction: column;
    z-index: 0;
  }

  /* ── Top Bar ─────────────────────────────────────── */
  #topbar {
    height: 28px;
    background: rgba(15, 15, 15, 0.95);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    color: #e0e0e0;
    font-size: 13px;
    z-index: 100;
    -webkit-app-region: drag;
  }
  #topbar .left { display: flex; align-items: center; gap: 16px; }
  #topbar .right { display: flex; align-items: center; gap: 14px; }
  #topbar .app-name { font-weight: 600; letter-spacing: 0.3px; }
  #topbar .clock { color: #ccc; font-variant-numeric: tabular-nums; }

  /* ── Taskbar / Dock ──────────────────────────────── */
  #taskbar {
    position: absolute;
    left: 0; bottom: 0;
    width: 52px;
    height: calc(100vh - 28px);
    background: rgba(15, 15, 15, 0.75);
    backdrop-filter: blur(14px);
    display: flex;
    flex-direction: column;
    align-items: center;
    padding-top: 12px;
    gap: 6px;
    z-index: 90;
    border-right: 1px solid rgba(255,255,255,0.06);
  }
  #taskbar .dock-sep {
    width: 32px; height: 1px;
    background: rgba(255,255,255,0.12);
    margin: 4px 0;
  }

  .dock-btn {
    width: 42px; height: 42px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s, transform 0.1s;
    position: relative;
  }
  .dock-btn:hover { background: rgba(255,255,255,0.1); }
  .dock-btn:active { transform: scale(0.93); }
  .dock-btn svg { width: 26px; height: 26px; }

  /* indicator dot when window is open */
  .dock-btn.open::after {
    content: '';
    position: absolute;
    left: -4px; top: 50%; transform: translateY(-50%);
    width: 3px; height: 16px;
    background: #e95660;
    border-radius: 2px;
  }

  /* ── Window base ─────────────────────────────────── */
  .window {
    position: absolute;
    min-width: 380px;
    min-height: 260px;
    background: #1e1e1e;
    border-radius: 10px;
    box-shadow: 0 12px 48px rgba(0,0,0,0.55), 0 0 0 1px rgba(255,255,255,0.06);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 50;
  }
  .window.hidden { display: none !important; }

  /* title bar */
  .win-titlebar {
    height: 38px;
    background: #2d2d2d;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 10px;
    cursor: default;
    -webkit-app-region: drag;
    flex-shrink: 0;
  }
  .win-titlebar .title {
    color: #ddd; font-size: 13px; font-weight: 500;
    display: flex; align-items: center; gap: 8px;
  }
  .win-titlebar .title svg { width: 16px; height: 16px; opacity: 0.7; }

  /* traffic-light buttons */
  .win-controls { display: flex; gap: 7px; -webkit-app-region: no-drag; }
  .win-controls button {
    width: 14px; height: 14px; border-radius: 50%; border: none; cursor: pointer;
    transition: opacity 0.12s;
  }
  .win-controls button:hover { opacity: 0.8; }
  .btn-close-win { background: #e95660; }
  .btn-minimize-win { background: #f4b942; }
  .btn-maximize-win { background: #33c15d; }

  /* window body */
  .win-body { flex: 1; overflow: auto; display: flex; flex-direction: column; }

  /* ── Files App ───────────────────────────────────── */
  #files-window { width: 680px; height: 460px; left: 120px; top: 70px; }

  .files-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 6px 12px; background: #252525; border-bottom: 1px solid #333;
  }
  #files-up {
    width: 30px; height: 30px; border-radius: 6px;
    background: transparent; border: 1px solid #444; color: #ddd;
    cursor: pointer; display: flex; align-items: center; justify-content: center;
    transition: background 0.12s;
  }
  #files-up:hover { background: rgba(255,255,255,0.08); }
  #files-up svg { width: 16px; height: 16px; }

  #files-path {
    flex: 1; height: 30px; line-height: 30px;
    background: #1a1a1a; border: 1px solid #444; border-radius: 6px;
    padding: 0 12px; color: #e8e8e8; font-size: 13px; font-family: 'Ubuntu Mono', monospace;
    outline: none;
  }
  #files-path:focus { border-color: #e95660; }

  .files-list {
    flex: 1; overflow-y: auto; padding: 4px 8px;
  }
  .fs-item {
    display: flex; align-items: center; gap: 10px;
    padding: 7px 12px; border-radius: 6px; cursor: default;
    color: #ddd; font-size: 13.5px; transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.05); }
  .fs-item svg { width: 20px; height: 20px; flex-shrink: 0; }
  .fs-item.folder svg { color: #f4b942; }
  .fs-item.file svg { color: #7eb8e0; }

  /* ── Notepad App ─────────────────────────────────── */
  #notepad-window { width: 640px; height: 440px; left: 180px; top: 90px; }

  .notepad-toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 5px 12px; background: #252525; border-bottom: 1px solid #333;
  }
  #new-tab {
    height: 28px; padding: 0 14px; border-radius: 6px;
    background: #e95660; border: none; color: #fff; font-size: 12.5px;
    cursor: pointer; font-weight: 500; transition: opacity 0.12s;
  }
  #new-tab:hover { opacity: 0.85; }

  #tabs {
    display: flex; align-items: center; gap: 2px;
    padding: 4px 12px 0; background: #252525; border-bottom: 1px solid #333;
    overflow-x: auto; flex-shrink: 0;
  }
  .tab {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 14px; border-radius: 7px 7px 0 0;
    background: transparent; color: #aaa; font-size: 12.5px;
    cursor: pointer; white-space: nowrap; transition: all 0.12s;
    border: 1px solid transparent; border-bottom: none;
  }
  .tab:hover { background: rgba(255,255,255,0.04); color: #ddd; }
  .tab.active { background: #1e1e1e; color: #fff; border-color: #333; font-weight: 500; }
  .tab .close-tab {
    width: 16px; height: 16px; border-radius: 50%; border: none;
    background: transparent; color: #888; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 14px; line-height: 1; transition: all 0.1s;
  }
  .tab .close-tab:hover { background: rgba(233,86,96,0.7); color: #fff; }

  #editor-wrap { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
  #editor {
    flex: 1; resize: none; border: none; outline: none;
    background: #1e1e1e; color: #d4d4d4; font-family: 'Ubuntu Mono', 'Fira Code', monospace;
    font-size: 13.5px; line-height: 1.65; padding: 14px 16px;
  }

  /* scrollbar */
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 4px; }
  ::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }

  /* ── Dragging state ──────────────────────────────── */
  .window.dragging { transition: none !important; z-index: 999; }
</style>
</head>
<body>

<!-- Desktop root -->
<div id="desktop">

  <!-- Top bar -->
  <div id="topbar">
    <div class="left">
      <span class="app-name">Ubuntu</span>
    </div>
    <div class="right">
      <span class="clock" id="clock"></span>
    </div>
  </div>

  <!-- Taskbar / Dock -->
  <div id="taskbar">
    <button class="dock-btn" id="open-files" title="Files">
      <svg viewBox="0 0 24 24" fill="none" stroke="#f4b942" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/>
      </svg>
    </button>

    <div class="dock-sep"></div>

    <button class="dock-btn" id="open-notepad" title="Notepad">
      <svg viewBox="0 0 24 24" fill="none" stroke="#7eb8e0" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
        <polyline points="14 2 14 8 20 8"/>
        <line x1="16" y1="13" x2="8" y2="13"/>
        <line x1="16" y1="17" x2="8" y2="17"/>
      </svg>
    </button>

    <div class="dock-sep"></div>

    <!-- Trash placeholder -->
    <button class="dock-btn" title="Trash">
      <svg viewBox="0 0 24 24" fill="none" stroke="#888" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">
        <polyline points="3 6 5 6 21 6"/>
        <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/>
      </svg>
    </button>
  </div>

  <!-- ═══ Files Window ═══ -->
  <div class="window hidden" id="files-window">
    <div class="win-titlebar">
      <span class="title">
        <svg viewBox="0 0 24 24" fill="#f4b942" width="16" height="16"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
        Files
      </span>
      <div class="win-controls">
        <button class="btn-minimize-win"></button>
        <button class="btn-maximize-win"></button>
        <button class="win-close" title="Close">&times;</button>
      </div>
    </div>
    <div class="win-body">
      <div class="files-toolbar">
        <button id="files-up" title="Go up one level">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><polyline points="15 18 9 12 15 6"/></svg>
        </button>
        <input id="files-path" type="text" readonly />
      </div>
      <div class="files-list" id="files-list"></div>
    </div>
  </div>

  <!-- ═══ Notepad Window ═══ -->
  <div class="window hidden" id="notepad-window">
    <div class="win-titlebar">
      <span class="title">
        <svg viewBox="0 0 24 24" fill="#7eb8e0" width="16" height="16"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
        Notepad
      </span>
      <div class="win-controls">
        <button class="btn-minimize-win"></button>
        <button class="btn-maximize-win"></button>
        <button class="win-close" title="Close">&times;</button>
      </div>
    </div>
    <div class="win-body">
      <div class="notepad-toolbar">
        <button id="new-tab">+ New Tab</button>
      </div>
      <div id="tabs"></div>
      <div id="editor-wrap">
        <textarea id="editor" spellcheck="false"></textarea>
      </div>
    </div>
  </div>

</div><!-- /#desktop -->

<script>
/* ═══════════════════════════════════════════════════
   Clock
   ═══════════════════════════════════════════════════ */
(function updateClock() {
  const el = document.getElementById('clock');
  function tick() {
    const now = new Date();
    el.textContent = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  tick(); setInterval(tick, 15000);
})();

/* ═══════════════════════════════════════════════════
   Window management helpers
   ═══════════════════════════════════════════════════ */
const filesWin = document.getElementById('files-window');
const notepadWin = document.getElementById('notepad-window');

function openWindow(win) {
  win.classList.remove('hidden');
}
function closeWindow(win) {
  win.classList.add('hidden');
}

// Dock buttons toggle windows
document.getElementById('open-files').addEventListener('click', () => {
  if (filesWin.classList.contains('hidden')) openWindow(filesWin);
});
document.getElementById('open-notepad').addEventListener('click', () => {
  if (notepadWin.classList.contains('hidden')) openWindow(notepadWin);
});

// Close buttons on each window
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', e => {
    const win = e.target.closest('.window');
    closeWindow(win);
  });
});

/* ── Draggable windows ───────────────────────────── */
let dragTarget = null, dragOffX = 0, dragOffY = 0;

document.querySelectorAll('.win-titlebar').forEach(tb => {
  tb.addEventListener('mousedown', e => {
    if (e.target.closest('.win-controls')) return;
    const win = tb.closest('.window');
    if (!win || win.classList.contains('hidden')) return;
    dragTarget = win;
    dragOffX = e.clientX - win.offsetLeft;
    dragOffY = e.clientY - win.offsetTop;
    win.classList.add('dragging');
  });
});

document.addEventListener('mousemove', e => {
  if (!dragTarget) return;
  let x = e.clientX - dragOffX;
  let y = e.clientY - dragOffY;
  // keep within viewport
  const maxLeft = window.innerWidth - dragTarget.offsetWidth;
  const maxTop = window.innerHeight - dragTarget.offsetHeight;
  x = Math.max(0, Math.min(x, maxLeft));
  y = Math.max(0, Math.min(y, maxTop));
  dragTarget.style.left = x + 'px';
  dragTarget.style.top = y + 'px';
});

document.addEventListener('mouseup', () => {
  if (dragTarget) {
    dragTarget.classList.remove('dragging');
    dragTarget = null;
  }
});

/* ═══════════════════════════════════════════════════
   Files App — fake filesystem
   ═══════════════════════════════════════════════════ */
const fs = {
  '/': ['bin','etc','home','usr','var'],
  '/bin': ['bash','cat','cp','ls','mkdir','mv','rm','sudo'],
  '/etc': ['hostname','hosts','passwd','fstab','shadow','resolv.conf'],
  '/home': ['user'],
  '/home/user': ['Documents','Downloads','Pictures','.config','.bashrc','.profile'],
  '/home/user/Documents': ['notes.txt','todo.md','report.pdf'],
  '/home/user/Downloads': ['ubuntu.iso','archive.tar.gz','image.png'],
  '/home/user/Pictures': ['wallpaper.jpg','screenshot.png','vacation/'],
  '/usr': ['bin','lib','share','local'],
  '/usr/bin': ['python3','node','gcc','git','vim'],
  '/usr/lib': ['x86_64-linux-gnu','python3.10'],
  '/var': ['log','cache','tmp','mail'],
  '/var/log': ['syslog','auth.log','kern.log'],
};

let currentPath = '/';

function getItems(path) { return fs[path] || []; }
function getParent(p) { if (p === '/') return null; const parts = p.split('/'); parts.pop(); return parts.join('/') || '/'; }

const folderIcon = `<svg viewBox="0 0 24 24" fill="#f4b942"><path d="M10 4H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>`;
const fileIcon = `<svg viewBox="0 0 24 24" fill="#7eb8e0"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8" fill="none" stroke="#7eb8e0" stroke-width="1.5"/></svg>`;

function renderFiles() {
  const list = document.getElementById('files-list');
  const pathInput = document.getElementById('files-path');
  pathInput.value = currentPath;

  const items = getItems(currentPath);
  list.innerHTML = '';

  if (items.length === 0) {
    list.innerHTML = '<div style="padding:24px;color:#666;font-size:13px;text-align:center;">This folder is empty</div>';
    return;
  }

  items.forEach(name => {
    const fullPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
    const isFolder = fs[fullPath] !== undefined;

    const el = document.createElement('div');
    el.className = 'fs-item' + (isFolder ? ' folder' : ' file');
    el.innerHTML = (isFolder ? folderIcon : fileIcon) + '<span>' + name + '</span>';

    // Double-click to navigate into folders
    if (isFolder) {
      el.addEventListener('dblclick', () => {
        currentPath = fullPath;
        renderFiles();
      });
    }

    list.appendChild(el);
  });
}

// Up button
document.getElementById('files-up').addEventListener('click', () => {
  const parent = getParent(currentPath);
  if (parent) {
    currentPath = parent;
    renderFiles();
  }
});

renderFiles();

/* ═══════════════════════════════════════════════════
   Notepad App — tabbed, localStorage-persistent
   ═══════════════════════════════════════════════════ */
const STORAGE_KEY = 'notepad-tabs';

function loadTabs() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch(e) { return null; }
}

function saveTabs(tabs) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
}

let tabs = loadTabs();
let activeTabId = null;

if (!tabs || tabs.length === 0) {
  // create one default tab
  const id = Date.now().toString(36);
  tabs = [{ id: id, name: 'Untitled', content: '' }];
  activeTabId = id;
  saveTabs(tabs);
} else {
  activeTabId = tabs[0].id;
}

function generateTabName() {
  const n = tabs.length + 1;
  return 'Tab ' + n;
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = '';

  tabs.forEach(tab => {
    const el = document.createElement('div');
    el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
    el.dataset.tabId = tab.id;

    const nameSpan = document.createElement('span');
    nameSpan.textContent = tab.name;

    const closeBtn = document.createElement('button');
    closeBtn.className = 'close-tab';
    closeBtn.innerHTML = '&times;';
    closeBtn.addEventListener('click', e => {
      e.stopPropagation();
      closeTab(tab.id);
    });

    el.appendChild(nameSpan);
    el.appendChild(closeBtn);

    el.addEventListener('click', () => {
      activeTabId = tab.id;
      renderTabs();
      syncEditor();
    });

    tabsEl.appendChild(el);
  });
}

function closeTab(id) {
  const idx = tabs.findIndex(t => t.id === id);
  if (idx === -1) return;
  tabs.splice(idx, 1);
  saveTabs(tabs);
  if (tabs.length === 0) {
    // create a fresh tab so the app isn't empty
    const newId = Date.now().toString(36);
    tabs = [{ id: newId, name: 'Untitled', content: '' }];
    activeTabId = newId;
    saveTabs(tabs);
  } else if (activeTabId === id) {
    // switch to nearest tab
    const newIdx = Math.min(idx, tabs.length - 1);
    activeTabId = tabs[newIdx].id;
  }
  renderTabs();
  syncEditor();
}

function createNewTab() {
  const id = Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
  const name = generateTabName();
  tabs.push({ id: id, name: name, content: '' });
  activeTabId = id;
  saveTabs(tabs);
  renderTabs();
  syncEditor();
}

function syncEditor() {
  const editor = document.getElementById('editor');
  const tab = tabs.find(t => t.id === activeTabId);
  if (tab) {
    // detach: don't overwrite while typing — only set when switching
    editor.value = tab.content;
  }
}

// Save content on input (debounced)
let saveTimeout = null;
document.getElementById('editor').addEventListener('input', () => {
  clearTimeout(saveTimeout);
  saveTimeout = setTimeout(() => {
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
      tab.content = document.getElementById('editor').value;
      saveTabs(tabs);
    }
  }, 300);
});

document.getElementById('new-tab').addEventListener('click', createNewTab);

// Initial render
renderTabs();
syncEditor();

/* ═══════════════════════════════════════════════════
   Dock open indicators
   ═══════════════════════════════════════════════════ */
function updateDockIndicators() {
  const filesBtn = document.getElementById('open-files');
  const notepadBtn = document.getElementById('open-notepad');

  if (!filesWin.classList.contains('hidden')) filesBtn.classList.add('open');
  else filesBtn.classList.remove('open');

  if (!notepadWin.classList.contains('hidden')) notepadBtn.classList.add('open');
  else notepadBtn.classList.remove('open');
}

// Watch for window visibility changes (close button)
const observer = new MutationObserver(updateDockIndicators);
observer.observe(filesWin, { attributes: true, attributeFilter: ['class'] });
observer.observe(notepadWin, { attributes: true, attributeFilter: ['class'] });
updateDockIndicators();

</script>
</body>
</html>
